{
  "domain_analysis": {
    "business_context": "A global logistics platform adding real-time earnings breakdown visibility for drivers across three jurisdictions with fundamentally different labor classifications, legal requirements, and governance structures. This is not a simple UI feature — it is a compensation disclosure system with legal, regulatory, and labor relations implications that vary by jurisdiction.",
    "bounded_context": "Driver Earnings & Compensation",
    "ubiquitous_language": [
      { "term": "Base Pay", "definition": "The fixed compensation component for a delivery task, calculated before bonuses, tips, or deductions. In employee jurisdictions (CA), this must meet or exceed minimum wage when calculated hourly." },
      { "term": "Per-Delivery Bonus", "definition": "Variable compensation tied to completion of individual deliveries (e.g., surge pricing, distance bonus, batch bonus). Distinct from tips." },
      { "term": "Tip", "definition": "Gratuity paid by the customer to the driver. Must NEVER be commingled with or subsidize base pay. In CA, tips cannot count toward minimum wage obligations." },
      { "term": "Deduction", "definition": "Any amount subtracted from gross earnings: equipment fees, insurance contributions, cash-on-delivery shortfalls, tax withholdings, etc. Deductions have fundamentally different legal constraints by jurisdiction and driver classification." },
      { "term": "Driver Classification", "definition": "The legal relationship between the platform and the driver — either Employee (CA under AB5) or Independent Contractor (Indonesia). This classification governs which earnings rules, tax treatments, and disclosure obligations apply." },
      { "term": "Earnings Period", "definition": "The time window over which earnings are aggregated for display. Must align with pay cycle (e.g., per-delivery, daily, weekly). Real-time display does not eliminate the need for period-based reconciliation." },
      { "term": "Works Council Approval", "definition": "In Germany, mandatory co-determination (Mitbestimmung) approval from the Betriebsrat before any system that monitors, evaluates, or displays worker compensation data can be deployed." },
      { "term": "Gross Earnings", "definition": "Base Pay + Per-Delivery Bonus + Tips, before any deductions." },
      { "term": "Net Earnings", "definition": "Gross Earnings minus all applicable Deductions. What the driver actually receives." },
      { "term": "Itemized Wage Statement", "definition": "In CA (Labor Code §226), employers must provide detailed, itemized pay stubs. The earnings breakdown display must satisfy or exceed this legal requirement." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Tips must never be used to subsidize or offset Base Pay. They must appear as a completely separate line item and must not be included in any minimum wage calculation.",
      "invariant": true,
      "invariant_justification": "Tip credit prohibition is a legal constraint in California (Labor Code §351) and a fundamental data integrity rule. If tips subsidize base pay, the system is producing fraudulent wage statements.",
      "testable_assertion": "For any earnings record, removing all tip amounts must not change the base pay value, and base pay alone (plus bonuses, excluding tips) must meet minimum wage when the driver is classified as an employee."
    },
    {
      "id": "BR-2",
      "rule": "Every Deduction must have a named category, a reason, and an authorizing reference (legal statute, contract clause, or driver consent record). No unnamed or unexplained deductions may appear.",
      "invariant": true,
      "invariant_justification": "Unexplained deductions constitute wage theft in employee jurisdictions and breach of contract in contractor jurisdictions. The system is corrupt if money disappears without attribution.",
      "testable_assertion": "For every deduction line item, the fields category, reason, and authorization_reference must be non-empty strings."
    },
    {
      "id": "BR-3",
      "rule": "In California, the earnings breakdown must satisfy all requirements of an itemized wage statement under Labor Code §226: gross wages, total hours worked, piece-rate units (deliveries), all deductions, net wages, pay period dates, employer name/address, and employee ID.",
      "invariant": true,
      "invariant_justification": "Failure to provide compliant wage statements exposes the platform to statutory penalties of $250 per violation per employee. This is a legal data completeness constraint — if any required field is missing, the statement is non-compliant.",
      "testable_assertion": "For any California driver earnings view, all fields mandated by §226 (gross_wages, hours_worked, piece_rate_units, deductions[], net_wages, pay_period_start, pay_period_end, employer_name, employer_address, employee_id) must be present and non-null."
    },
    {
      "id": "BR-4",
      "rule": "The earnings breakdown display must NOT be deployed in Germany until Works Council (Betriebsrat) approval is obtained and recorded in the system. The feature must be gated by jurisdiction with an explicit approval flag.",
      "invariant": true,
      "invariant_justification": "Deploying a compensation display system without Works Council approval violates the Betriebsverfassungsgesetz (Works Constitution Act) §87. This is not a policy preference — it is a legal precondition. Deploying without approval could result in injunctions and invalidation of the system.",
      "testable_assertion": "The feature flag for Germany must check works_council_approval_status === 'approved' AND approval_date is non-null before rendering any earnings data to German drivers."
    },
    {
      "id": "BR-5",
      "rule": "Gross Earnings = Base Pay + Per-Delivery Bonus + Tips. Net Earnings = Gross Earnings - sum(Deductions). These arithmetic identities must hold exactly for every earnings record displayed.",
      "invariant": true,
      "invariant_justification": "If the displayed breakdown does not sum correctly, the driver is seeing falsified financial data. This is a data integrity constraint — arithmetic inconsistency means the system is corrupt.",
      "testable_assertion": "For every earnings record: assert(gross_earnings == base_pay + per_delivery_bonus + tips) AND assert(net_earnings == gross_earnings - sum(deductions))."
    },
    {
      "id": "BR-6",
      "rule": "For California employee-classified drivers, base pay calculated on an hourly basis must meet or exceed the applicable minimum wage (state or local, whichever is higher) for all hours worked.",
      "invariant": true,
      "invariant_justification": "Displaying earnings that reflect sub-minimum-wage pay without flagging it would make the platform complicit in a wage violation. The display system must never normalize illegal compensation.",
      "testable_assertion": "For any CA driver earnings period: assert(base_pay / hours_worked >= applicable_minimum_wage). If this fails, the system must flag the record for payroll review rather than silently displaying it."
    },
    {
      "id": "BR-7",
      "rule": "The earnings breakdown must display in real time, defined as updated within 60 seconds of a delivery completion, tip update, or deduction event.",
      "invariant": false,
      "invariant_justification": "The 60-second SLA is a product quality target, not a legal or data integrity constraint. A VP could adjust this to 5 minutes without corrupting the system.",
      "testable_assertion": "After a delivery_completed, tip_received, or deduction_applied event, the driver's earnings view must reflect the change within 60 seconds."
    },
    {
      "id": "BR-8",
      "rule": "Earnings data must be displayed in the local currency of the jurisdiction where the delivery was performed (USD for California, EUR for Germany, IDR for Indonesia).",
      "invariant": true,
      "invariant_justification": "Displaying earnings in a foreign currency would be misleading and potentially constitute fraudulent wage disclosure. The driver must see what they are actually being paid in their local denomination.",
      "testable_assertion": "For each earnings record, assert(currency == jurisdiction.local_currency)."
    },
    {
      "id": "BR-9",
      "rule": "For Indonesian independent contractors, the earnings breakdown must clearly label the relationship as 'Independent Contractor' and must NOT display employer tax withholdings, benefits deductions, or any fields that imply an employment relationship.",
      "invariant": true,
      "invariant_justification": "Displaying employment-style deductions for contractors creates legal risk of reclassification. If the UI implies an employment relationship where none exists, it could be used as evidence of misclassification.",
      "testable_assertion": "For any Indonesian driver earnings view: driver_classification must equal 'independent_contractor', and the deductions list must not contain items of type 'income_tax_withholding', 'health_insurance', 'social_security', or 'employer_benefit'."
    },
    {
      "id": "BR-10",
      "rule": "All earnings data displayed must be auditable — every line item must be traceable to a source event (delivery ID, tip transaction ID, deduction authorization ID) stored immutably.",
      "invariant": true,
      "invariant_justification": "Without audit trails, earnings disputes cannot be resolved, and wage statement compliance cannot be verified. This is a data integrity and legal evidentiary requirement.",
      "testable_assertion": "Every line item in the earnings breakdown must have a non-null source_event_id that resolves to an existing, immutable event record."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A California-based employee driver has completed 3 deliveries today with base pay, bonuses, 2 tips, and 1 deduction",
      "when": "The driver views their earnings breakdown",
      "then": "All line items are displayed with correct categorization (base pay, bonus, tips, deductions separately), the arithmetic sums are correct, all §226 required fields are present, and tips are shown as a distinct category not included in base pay calculations"
    },
    {
      "id": "AC-2",
      "given": "The Germany jurisdiction has works_council_approval_status = 'pending'",
      "when": "A German driver attempts to view the earnings breakdown feature",
      "then": "The feature is not accessible; the driver sees a message indicating the feature is not yet available in their region, with no earnings data exposed"
    },
    {
      "id": "AC-3",
      "given": "The Germany jurisdiction has works_council_approval_status = 'approved' with a valid approval_date",
      "when": "A German driver views their earnings breakdown",
      "then": "The full earnings breakdown is displayed in EUR with all line items, and the driver classification reflects the applicable German labor relationship"
    },
    {
      "id": "AC-4",
      "given": "An Indonesian independent contractor driver has completed deliveries",
      "when": "The driver views their earnings breakdown",
      "then": "The breakdown displays in IDR, labels the driver as 'Independent Contractor', shows base pay + bonuses + tips - platform fees, and does NOT display any employment-style withholdings or benefit deductions"
    },
    {
      "id": "AC-5",
      "given": "A driver has just completed a delivery and a customer has added a tip",
      "when": "The driver views their earnings breakdown within 60 seconds",
      "then": "Both the delivery earnings and the tip are reflected in the real-time view"
    },
    {
      "id": "AC-6",
      "given": "A California driver's base pay for the current period, divided by hours worked, falls below the applicable minimum wage",
      "when": "The earnings breakdown is calculated for display",
      "then": "The system flags this record for payroll review and does NOT display the earnings as normal/accepted — it surfaces a compliance alert"
    },
    {
      "id": "AC-7",
      "given": "Any driver in any jurisdiction views their earnings breakdown",
      "when": "They see a deduction line item",
      "then": "The deduction shows a category name, a human-readable reason, and the authorization basis — no unexplained deductions are ever displayed"
    },
    {
      "id": "AC-8",
      "given": "Any driver views their earnings breakdown",
      "when": "They check the totals",
      "then": "Gross = Base Pay + Bonuses + Tips, and Net = Gross - Deductions, with exact arithmetic match (no floating-point display errors)"
    }
  ],

  "edge_cases": [
    {
      "scenario": "A delivery spans midnight and crosses two pay periods",
      "expected_behavior": "The earnings for that delivery must be attributed to exactly one pay period based on delivery completion timestamp, not split across periods. The chosen period must be consistent and documented."
    },
    {
      "scenario": "A customer modifies a tip after the driver has already viewed their earnings",
      "expected_behavior": "The earnings breakdown must update to reflect the revised tip. The previous tip amount is replaced (not shown as a deduction). An audit trail of the change is maintained but the driver sees the current correct state."
    },
    {
      "scenario": "A deduction is applied retroactively to a previous pay period",
      "expected_behavior": "The deduction appears in the current period with a clear label indicating it is a retroactive adjustment referencing the original period. It must not silently alter historical earnings records that the driver has already seen."
    },
    {
      "scenario": "A driver performs deliveries in California, then drives to Nevada (different jurisdiction) in the same day",
      "expected_behavior": "Each delivery's earnings must be governed by the jurisdiction where that specific delivery was performed. The breakdown must not blend rules across jurisdictions."
    },
    {
      "scenario": "Works Council approval in Germany is granted, then revoked mid-rollout",
      "expected_behavior": "The feature must be immediately disabled for all German drivers. The approval flag must support revocation, not just grant. Previously displayed data need not be recalled, but no new data is shown until re-approval."
    },
    {
      "scenario": "Network latency causes the real-time update to exceed the 60-second SLA",
      "expected_behavior": "The system should display the last known correct state with a visible 'last updated' timestamp, never show stale data without indicating staleness, and never show partially updated data."
    },
    {
      "scenario": "A driver has zero earnings for the current period (no completed deliveries)",
      "expected_behavior": "The earnings breakdown displays all categories at zero/empty. It does not show an error or hide the view. The driver should still see the structure so they understand what to expect."
    },
    {
      "scenario": "Indonesia changes its labor classification laws to require driver reclassification as employees",
      "expected_behavior": "The jurisdiction configuration must be updatable without code changes. The system must support per-jurisdiction classification that can be changed by operations, triggering the appropriate earnings display rules for the new classification."
    }
  ],

  "business_impact": {
    "financial": "California non-compliance with §226 carries penalties of $250/violation/employee (initial) and $1,000/subsequent. With thousands of drivers, a systematic failure could mean millions in penalties. Germany deployment without Works Council approval risks injunctions halting operations. Proper transparency may also reduce earnings disputes and support ticket costs.",
    "operational": "Three distinct jurisdiction configurations must be maintained. The Germany approval gate adds a dependency on an external governance process with unpredictable timelines. Real-time update requirements demand event-driven architecture, not batch processing. Audit trail requirements add storage and compliance overhead.",
    "user": "Drivers gain trust and engagement through transparent earnings. In California, this fulfills a legal right. In Indonesia, this is a competitive differentiator (not legally required). Poor implementation (incorrect sums, confusing deductions) would erode trust more than having no feature at all.",
    "risk": "HIGH — This feature touches wage law, labor classification, and co-determination rights across three jurisdictions. Legal exposure is significant if rules are applied to the wrong jurisdiction, if the Germany gate fails open, or if tip/base pay separation is violated in California. Classification leakage (showing employee-style data to contractors) creates reclassification risk.",
    "stakeholders_affected": [
      { "group": "Drivers (California)", "impact": "Gain legally required wage transparency; incorrect implementation violates their statutory rights" },
      { "group": "Drivers (Germany)", "impact": "Feature delayed until Works Council approval; premature deployment violates their co-determination rights" },
      { "group": "Drivers (Indonesia)", "impact": "Gain voluntary earnings visibility; incorrect classification framing could trigger regulatory scrutiny" },
      { "group": "Legal & Compliance Team", "impact": "Must validate jurisdiction-specific rules, approve deduction categories, and monitor for classification leakage" },
      { "group": "Works Council (Germany)", "impact": "Must be formally consulted and must approve before any deployment; their timeline controls the Germany launch" },
      { "group": "Payroll & Finance", "impact": "Earnings displayed must exactly match payroll records; any discrepancy creates disputes and reconciliation burden" },
      { "group": "Platform Operations", "impact": "Must maintain jurisdiction configurations, feature flags, and approval gates as an ongoing operational concern" },
      { "group": "Customer Support", "impact": "Will receive increased inquiries about earnings calculations; needs documentation and training on the new display" }
    ]
  },

  "confidence": {
    "level": 52,
    "reasoning": "The spec is dangerously underspecified for a feature with this level of legal exposure. It mentions three jurisdictions but provides no detail on German driver classification (employee? contractor? mini-job?), gives no spec for what deduction categories exist, does not address data retention or historical access requirements, and says nothing about how real-time is defined or what happens when it fails. The legal requirements cited (AB5, Betriebsrat, §226) are real and well-established, but the spec does not indicate whether legal counsel has reviewed the feature requirements. Multiple critical details must be resolved before implementation.",
    "high_confidence_areas": [
      "California tip separation from base pay is a hard legal requirement",
      "Works Council approval is a mandatory precondition for Germany deployment",
      "Arithmetic integrity of earnings breakdown is a universal invariant",
      "Indonesian contractors must not see employment-style deductions"
    ],
    "low_confidence_areas": [
      "German driver classification is unspecified — employee, contractor, or mixed?",
      "Deduction categories and authorization model are entirely undefined",
      "Data retention requirements for historical earnings views not addressed",
      "Definition of 'real time' and failure modes not specified",
      "Tax display rules per jurisdiction not specified",
      "Whether this feature replaces or supplements existing pay stubs is unclear"
    ],
    "assumptions": [
      "German drivers are classified as employees (typical for the market, but not confirmed)",
      "The 60-second real-time SLA is a reasonable product target in absence of spec",
      "The platform already has a payroll system that this feature reads from, rather than being the source of truth for compensation",
      "Legal review has not yet been conducted on the specific display requirements"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "German driver classification is not specified. Are they employees, independent contractors, or a mix? This fundamentally changes what fields must appear in the earnings breakdown, what deductions are valid, and what tax withholdings to display.",
      "affected_stakeholders": ["Drivers (Germany)", "Legal & Compliance Team", "Works Council (Germany)"],
      "options": [
        "A: Assume employee classification (most common in German logistics) and apply employee-style breakdown with tax withholdings",
        "B: Treat as a configurable parameter per jurisdiction that must be set before feature activation",
        "C: Block Germany implementation until classification is explicitly confirmed"
      ],
      "recommendation": "Option B — make classification a required jurisdiction configuration parameter. This is safest and most extensible."
    },
    {
      "type": "ambiguity",
      "description": "The spec says 'deductions' but does not define what categories of deductions exist, who authorizes them, or what the approval workflow is. Deductions are the highest-risk component of this feature — unauthorized deductions constitute wage theft.",
      "affected_stakeholders": ["All drivers", "Legal & Compliance Team", "Payroll & Finance"],
      "options": [
        "A: Define a closed set of allowed deduction categories per jurisdiction, each requiring legal pre-approval",
        "B: Allow free-form deductions with a required reason field",
        "C: Block deduction display until a deduction taxonomy is approved by legal"
      ],
      "recommendation": "Option A — a closed, jurisdiction-specific deduction taxonomy is the only safe approach. Free-form deductions will inevitably include unauthorized categories."
    },
    {
      "type": "missing_context",
      "description": "No indication of whether legal counsel has reviewed these jurisdiction-specific requirements. California wage statement law (§226), German co-determination law (BetrVG §87), and Indonesian contractor regulations each require legal sign-off before implementation.",
      "affected_stakeholders": ["All drivers", "Legal & Compliance Team", "Platform Operations"],
      "options": [
        "A: Proceed with implementation based on publicly known legal requirements and get legal review before launch",
        "B: Block all implementation until legal review is completed for each jurisdiction"
      ],
      "recommendation": "Option A — begin implementation with legal review as a parallel workstream, but make legal sign-off a launch gate (not a development gate)."
    },
    {
      "type": "ambiguity",
      "description": "The relationship between this earnings breakdown display and existing payroll/pay stub systems is undefined. Does this replace pay stubs? Supplement them? If both exist and show different numbers, which is authoritative?",
      "affected_stakeholders": ["All drivers", "Payroll & Finance", "Customer Support"],
      "options": [
        "A: This is a real-time view only; official pay stubs remain the legal record",
        "B: This replaces pay stubs and becomes the legal wage statement",
        "C: This supplements pay stubs but must be arithmetically consistent with them"
      ],
      "recommendation": "Option C — supplement existing pay stubs with mandatory consistency. Making this the legal wage statement (Option B) adds enormous regulatory burden that is likely unintended."
    }
  ],

  "rejection_reasons": []
}

